def install_same_tenant_guards(apps, schema_editor):
    """Add PostgreSQL triggers that prevent cross-tenant parent links."""
    if schema_editor.connection.vendor != "postgresql":
        return
    schema_editor.execute(r"""
        CREATE FUNCTION document_intelligence_require_same_tenant()
        RETURNS TRIGGER
        LANGUAGE plpgsql
        AS $$
        DECLARE
            parent_id UUID;
            parent_tenant UUID;
        BEGIN
            parent_id := (to_jsonb(NEW) ->> TG_ARGV[0])::UUID;
            IF parent_id IS NULL THEN
                RETURN NEW;
            END IF;
            EXECUTE format('SELECT tenant_id FROM %I WHERE id = $1', TG_ARGV[1])
               INTO parent_tenant
              USING parent_id;
            IF parent_tenant IS NULL OR parent_tenant <> NEW.tenant_id THEN
                RAISE EXCEPTION 'cross-tenant document-intelligence relationship rejected'
                    USING ERRCODE = '23514';
            END IF;
            RETURN NEW;
        END;
        $$;
        """)
    for child_table, fk_column, parent_table in SAME_TENANT_RELATIONSHIPS:
        trigger_name = f"docintel_same_tenant_{fk_column}_{child_table[-12:]}"
        quoted_trigger = schema_editor.quote_name(trigger_name)
        quoted_child = schema_editor.quote_name(child_table)
        quoted_fk = schema_editor.quote_name(fk_column)
        schema_editor.execute(f"""
            CREATE TRIGGER {quoted_trigger}
            BEFORE INSERT OR UPDATE OF tenant_id, {quoted_fk} ON {quoted_child}
            FOR EACH ROW EXECUTE FUNCTION document_intelligence_require_same_tenant(
                '{fk_column}', '{parent_table}'
            );
            """)


def remove_same_tenant_guards(apps, schema_editor):
    """Remove only the relationship guards owned by this module."""
    if schema_editor.connection.vendor != "postgresql":
        return
    for child_table, fk_column, _parent_table in reversed(SAME_TENANT_RELATIONSHIPS):
        trigger_name = f"docintel_same_tenant_{fk_column}_{child_table[-12:]}"
        schema_editor.execute(
            f"DROP TRIGGER IF EXISTS {schema_editor.quote_name(trigger_name)} "
            f"ON {schema_editor.quote_name(child_table)};"
        )
    schema_editor.execute("DROP FUNCTION IF EXISTS document_intelligence_require_same_tenant();")


